function generateQRCodes() {
  // --- Configuration ---
  const sourceSheetName = 'Sheet1'; // <-- Name of the tab with your paths
  const outputSheetName = 'Sheet1'; // <-- Name of the tab where you want QR codes (can be the same)
  const pathColumnIndex = 3; // <-- Column index (0-based) of the "Path" column (D is 3)
  const qrImageColumnIndex = 5; // <-- Column index (0-based) where QR image formula will go (F is 5)
  const startRow = 2; // <-- Row number to start processing (usually 2 to skip headers)
  const qrSize = '150x150'; // <-- Desired size of the QR code image

  // Get the active spreadsheet
  const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
  const sourceSheet = spreadsheet.getSheetByName(sourceSheetName);
  const outputSheet = spreadsheet.getSheetByName(outputSheetName);

  if (!sourceSheet || !outputSheet) {
    Logger.log("Error: Source or output sheet not found. Check sheet names.");
    return;
  }

  // Get data from the source sheet
  const lastRow = sourceSheet.getLastRow();
  if (lastRow < startRow) {
    Logger.log("No data to process in the source sheet.");
    return;
  }

  // Get the range of paths
  const pathsRange = sourceSheet.getRange(startRow, pathColumnIndex + 1, lastRow - startRow + 1, 1);
  const paths = pathsRange.getValues();

  // Prepare the array for the output formulas
  const qrFormulas = [];

  // Loop through each path and generate the QR code URL
  for (let i = 0; i < paths.length; i++) {
    const path = paths[i][0]; // Get the path string from the array

    if (path && typeof path === 'string' && path.trim() !== '') {
      // URL-encode the path
      const encodedPath = encodeURIComponent(path.trim());

      // Construct the QR code image URL using Google Chart API
      // Note: Google Chart API is deprecated but simple for this purpose.
      // For production, consider a more robust API or service.
      const qrUrl = `https://chart.googleapis.com/chart?chs=${qrSize}&cht=qr&chl=${encodedPath}`;

      // Construct the Google Sheets IMAGE formula
      // =IMAGE("QR_IMAGE_URL")
      const imageFormula = `=IMAGE("${qrUrl}")`;
      qrFormulas.push([imageFormula]);

    } else {
      // If the path is empty or invalid, put an empty string in the output column
      qrFormulas.push(['']);
    }
  }

  // Write the formulas to the output sheet
  const outputRange = outputSheet.getRange(startRow, qrImageColumnIndex + 1, qrFormulas.length, 1);
  outputRange.setValues(qrFormulas);

  Logger.log(`QR code formulas generated for ${qrFormulas.length} rows.`);
}

# --------------------------------------------------------------------
#  Consolidated New Workstation Data Script  v7.0.3
# --------------------------------------------------------------------
function Get-MonitorId {
    $monInfo = Get-CimInstance -Namespace root\wmi -Class WmiMonitorID

    foreach ($m in $monInfo) {

        # 1) Real EDID serial
        $bytes = $m.SerialNumberID | Where-Object { $_ }
        if ($bytes.Count -ge 4) {
            $serial = (-join ([char[]]$bytes)).Trim()
            if ($serial -match '\w{4,}') { $serial; continue }
        }

        # 2) Descriptor block
        try {
            $desc = Get-CimInstance -Namespace root\wmi `
                    -Class WmiMonitorDescriptorMethods |
                    Where-Object { $_.InstanceName -eq $m.InstanceName } |
                    ForEach-Object {
                        [Text.Encoding]::ASCII.GetString(
                            $_.GetMonitorDescriptor(0,0).Descriptor
                        ) -replace '[^\x20-\x7E]'
                    }
            if ($desc) { $desc; continue }
        } catch {}

        # 3) MODEL‑style fallback
        $vendor = (-join ([char[]]($m.ManufacturerName | Where-Object { $_ }))).Trim()
        $prodRaw = if ($m.ProductCodeID -is [array]) { $m.ProductCodeID[0] } else { $m.ProductCodeID }
        $prodId  = '{0:X4}' -f $prodRaw
        "MODEL:$vendor$prodId"
    }
}

# --------------------------------------------------------------------
#  Main collection block
# --------------------------------------------------------------------
$sn   = (Get-CimInstance Win32_BIOS).SerialNumber
$hn   = $env:COMPUTERNAME
$net  = Get-CimInstance Win32_NetworkAdapterConfiguration |
        Where-Object { $_.IPEnabled }
$mac  = $net.MACAddress
$ip   = $net.IPAddress | Where-Object { $_ -match '^\d{1,3}(\.\d{1,3}){3}$' } | Sort-Object -Unique
$mon  = Get-MonitorId | Sort-Object -Unique

Write-Host "Hostname          : $hn"
Write-Host "Serial            : $sn"
Write-Host "MAC(s)            : $($mac -join ', ')"
Write-Host "IP(s)             : $($ip  -join ', ')"
Write-Host "Monitor ID(s)     : $($mon -join ', ')"

# --------------------------------------------------------------------
#  Monitor helper – v7.0.4
# --------------------------------------------------------------------
# This script collects and displays information about the computer and its connected monitors.
# It tries to show details like monitor type (HDMI, DisplayPort, etc.), serial numbers, and more.

function Get-MonitorInfo {
    param(
        [switch]$IncludeConnection = $true  # Set to $false if WMI is locked down or you don't want connection info
    )

    # --- WMI pulls ---------------------------------------------------
    # Get monitor identification info (EDID) from Windows Management Instrumentation (WMI)
    $edid = Get-CimInstance -Namespace root\wmi -Class WmiMonitorID
    # Optionally, get connection type info for each monitor
    $conn = if ($IncludeConnection) {
        Get-CimInstance -Namespace root\wmi -Class WmiMonitorConnectionParams |
        Group-Object -Property InstanceName -AsHashTable -AsString
    }

    # DXGI -> friendly text mapping (most common codes)
    # This table converts numeric codes from Windows into human-readable connection types
    $techMap = @{
        '-2' = 'UNINITIALIZED';  '-1' = 'OTHER'
        '0'   = 'VGA/HD-15'         # Old analog connector
        '1'   = 'S-VIDEO'           # Legacy video
        '2'   = 'COMPOSITE'         # Legacy video
        '3'   = 'COMPONENT'         # Legacy video
        '4'   = 'DVI'               # Digital Visual Interface
        '5'   = 'HDMI'              # Common modern connector
        '10'  = 'DISPLAYPORT'       # Common modern connector
        '11'  = 'DP (embedded)'     # Embedded DisplayPort
        '13'  = 'eDP'               # Embedded DisplayPort (laptop screens)
        '16'  = 'USB-C/Alt-DP'      # USB-C with DisplayPort Alt Mode
        # high bit = internal laptop panel
        '2147483648' = 'INTERNAL'   # Internal laptop display (special code)
    }

    $idx = 1
    foreach ($m in $edid) {
        # --- build a unique, printable identifier (same logic as v7.0.3) ----
        $id = $null

        # 1) Try to get the real EDID serial number (most unique)
        $bytes = $m.SerialNumberID | Where-Object { $_ }
        if ($bytes.Count -ge 4) {
            $id = (-join ([char[]]$bytes)).Trim()
            if (-not ($id -match '\w{4,}')) {
                $id = $null
            }
        }

        # 2) If no serial, try to get the monitor's on-screen label from its descriptor
        if (-not $id) {
            try {
                $id = Get-CimInstance -Namespace root\wmi -Class WmiMonitorDescriptorMethods |
                    Where-Object { $_.InstanceName -eq $m.InstanceName } |
                    ForEach-Object {
                        [Text.Encoding]::ASCII.GetString(
                            $_.GetMonitorDescriptor(0,0).Descriptor
                        ) -replace '[^\x20-\x7E]'
                    } | Select-Object -First 1
            } catch {}
        }

        # 3) If all else fails, build a fallback ID from vendor and product code
        if (-not $id) {
            $vendor = (-join ([char[]]($m.ManufacturerName | Where-Object { $_ }))).Trim()
            $prodRaw = if ($m.ProductCodeID -is [array]) { $m.ProductCodeID[0] } else { $m.ProductCodeID }
            $prod = '{0:X4}' -f $prodRaw
            $id = "MODEL:$vendor$prod"
        }

        # --- optional connection type ---------------------------------------
        $tech = ''
        if ($IncludeConnection -and $conn[$m.InstanceName]) {
            # Get the numeric code for the connection type
            $code = [string]$conn[$m.InstanceName].VideoOutputTechnology
            # Convert the code to a friendly name if possible
            if ($techMap.ContainsKey($code)) {
                $tech = $techMap[$code]
            } else {
                $tech = "Code:$code"  # Show the raw code if unknown
            }

            # --- USB-C vs native DP refinement ----------------------------------
            # If it's DisplayPort, try to detect if it's really USB-C carrying DisplayPort (DP-Alt)
            if ($tech -eq 'DISPLAYPORT') {

                # Try to get more info from the device location (works without admin)
                $usbHint = Get-CimInstance -ClassName Win32_PnPEntity `
                        -Filter "DeviceID='$($m.InstanceName)'" `
                        -ErrorAction SilentlyContinue |
                        Select-Object -ExpandProperty LocationInformation -ErrorAction SilentlyContinue

                if (-not $usbHint) {
                    # If that fails, try a more advanced method (may require admin rights)
                    try {
                        $pnp = Get-PnpDevice -InstanceId $m.InstanceName -ErrorAction Stop
                        $usbHint = $pnp.LocationPath
                    } catch {}
                }

                # If the location info mentions USB, TYPEC, or TBT (Thunderbolt), label as USB-C (DP-Alt)
                if ($usbHint -match 'USB|TYPEC|TBT') {
                    $tech = 'USB-C (DP-Alt)'
                }
            }
        }

        # Output a PowerShell object for each monitor, with index, identifier, and connection type
        [pscustomobject]@{
            Idx        = $idx++
            Identifier = $id
            Connection = $tech
        }
    }
}

# --------------------------------------------------------------------
#  Example use in Main collection block
# --------------------------------------------------------------------
# This block collects system info and prints it, along with monitor info, to the console.
try {
    $sn  = (Get-CimInstance Win32_BIOS).SerialNumber   # Computer serial number
    $hn  = $env:COMPUTERNAME                          # Hostname
    $net = Get-CimInstance Win32_NetworkAdapterConfiguration | Where-Object { $_.IPEnabled }  # Network info
    $mac = $net.MACAddress                            # MAC address(es)
    $ip  = $net.IPAddress | Where-Object { $_ -match '^\d{1,3}(\.\d{1,3}){3}$' } | Sort-Object -Unique  # IPv4 addresses
    $mon = Get-MonitorInfo              # Get monitor info (duplicates kept, numbered, connection shown)

    Write-Host "Hostname          : $hn"
    Write-Host "Serial            : $sn"
    Write-Host "MAC(s)            : $($mac -join ', ')"
    Write-Host "IP(s)             : $($ip -join ', ')"
    $mon | ForEach-Object {
        $label = if ($_.Connection) { "$($_.Identifier) [$($_.Connection)]" } else { $_.Identifier }
        Write-Host ("Monitor #{0,-2}     : {1}" -f $_.Idx, $label)
    }
} catch {
    Write-Host "Error: $_"
}

# --------------------------------------------------------------------
#  Get‑MonitorId  :  returns a best-effort ID for every active display
#                   1) Real EDID serial   2) EDID descriptor text
#                   3) MODEL:<Vendor><ProductID> fallback
# --------------------------------------------------------------------
function Get-MonitorId {

    $monInfo = Get-CimInstance -Namespace root\wmi -Class WmiMonitorID

    foreach ($m in $monInfo) {

        # -- 1. EDID serial ---------------------------------------------------
        $bytes = $m.SerialNumberID | Where-Object { $_ }        # strip 0s
        if ($bytes.Count -ge 4) {
            $serial = (-join ([char[]]$bytes)).Trim()
            if ($serial -match '\w{4,}') {                      # sanity
                $serial
                continue
            }
        }

        # -- 2. Descriptor block 0/0 -----------------------------------------
        try {
            $desc = Get-CimInstance -Namespace root\wmi `
                    -Class WmiMonitorDescriptorMethods |
                    Where-Object { $_.InstanceName -eq $m.InstanceName } |
                    ForEach-Object {
                        [Text.Encoding]::ASCII.GetString(
                            $_.GetMonitorDescriptor(0,0).Descriptor
                        ) -replace '[^\x20-\x7E]'
                    }
            if ($desc) { $desc; continue }
        } catch {}

        # -- 3. MODEL fallback -----------------------------------------------
        $vendorBytes = $m.ManufacturerName | Where-Object { $_ }
        $vendor      = (-join ([char[]]$vendorBytes)).Trim()    # e.g. LEN
        $prodId      = '{0:X4}' -f $m.ProductCodeID             # e.g. 403D
        "MODEL:$vendor$prodId"
    }
}

# --------------------------------------------------------------------
#  Main collection block
# --------------------------------------------------------------------
$sn   = (Get-CimInstance Win32_BIOS).SerialNumber
$hn   = $env:COMPUTERNAME
$net  = Get-CimInstance Win32_NetworkAdapterConfiguration | Where IPEnabled
$mac  = $net.MACAddress
$ip   = $net.IPAddress | Where { $_ -match '^\d{1,3}(\.\d{1,3}){3}$' } | Sort -Unique
$mon  = Get-MonitorId | Sort -Unique

Write-Host "Hostname          : $hn"
Write-Host "Serial            : $sn"
Write-Host "MAC(s)            : $($mac -join ', ')"
Write-Host "IP(s)             : $($ip  -join ', ')"
Write-Host "Monitor ID(s)     : $($mon -join ', ')"

